package main

import (
	"fmt"
	"strings"
)

// genHeader is the standard Go "generated file" marker. It must precede the
// package clause to be recognized by gofmt/golangci-lint/go tooling, so that
// these files are treated as generated (not hand-edited, not linted).
const genHeader = "// Code generated by internal/gen. DO NOT EDIT.\n"

func modelField(f field) string {
	return fmt.Sprintf("\t%s %s `tfsdk:%q`", f.GoName, f.GoType, f.Name)
}

func resAttr(f field) string {
	switch f.Kind {
	case "required":
		switch f.GoType {
		case "types.List":
			return fmt.Sprintf("%q: schema.ListAttribute{ElementType: types.StringType, Required: true, Description: %q},", f.Name, f.Desc)
		case "types.Int64":
			return fmt.Sprintf("%q: schema.Int64Attribute{Required: true, Description: %q},", f.Name, f.Desc)
		case "types.Bool":
			return fmt.Sprintf("%q: schema.BoolAttribute{Required: true, Description: %q},", f.Name, f.Desc)
		default:
			return fmt.Sprintf("%q: schema.StringAttribute{Required: true, Description: %q},", f.Name, f.Desc)
		}
	case "optcomp":
		switch f.GoType {
		case "types.List":
			return fmt.Sprintf("%q: optionalComputedStringList(%q),", f.Name, f.Desc)
		case "types.Int64":
			return fmt.Sprintf("%q: optionalComputedInt64(%q),", f.Name, f.Desc)
		case "types.Bool":
			return fmt.Sprintf("%q: optionalComputedBool(%q),", f.Name, f.Desc)
		default:
			return fmt.Sprintf("%q: optionalComputedString(%q),", f.Name, f.Desc)
		}
	case "writeonly":
		return fmt.Sprintf("%q: schema.StringAttribute{Optional: true, Sensitive: true, Description: %q},", f.Name, f.Desc)
	case "createonly":
		dep := ""
		if f.Deprecated {
			dep = fmt.Sprintf(" DeprecationMessage: %q,", f.Desc)
		}
		return fmt.Sprintf("%q: schema.StringAttribute{Optional: true, PlanModifiers: []planmodifier.String{stringplanmodifier.RequiresReplace()}, Description: %q,%s},", f.Name, f.Desc, dep)
	case "computedbool":
		return fmt.Sprintf("%q: schema.BoolAttribute{Computed: true, Description: %q},", f.Name, f.Desc)
	default: // computedstring
		return fmt.Sprintf("%q: schema.StringAttribute{Computed: true, Description: %q},", f.Name, f.Desc)
	}
}

func dsAttr(f field) string {
	switch f.Kind {
	case "writeonly":
		return fmt.Sprintf("%q: dsschema.StringAttribute{Computed: true, Sensitive: true, Description: \"Always null; never returned by the API.\"},", f.Name)
	case "computedbool":
		return fmt.Sprintf("%q: dsComputedBool(%q),", f.Name, f.Desc)
	}
	switch f.GoType {
	case "types.List":
		return fmt.Sprintf("%q: dsComputedStringList(%q),", f.Name, f.Desc)
	case "types.Int64":
		return fmt.Sprintf("%q: dsComputedInt64(%q),", f.Name, f.Desc)
	case "types.Bool":
		return fmt.Sprintf("%q: dsComputedBool(%q),", f.Name, f.Desc)
	default:
		return fmt.Sprintf("%q: dsComputedString(%q),", f.Name, f.Desc)
	}
}

// bodyStmt emits a put into the request map; mv is the model var, mp the map var.
func bodyStmt(f field, mv, mp string) string {
	if f.Kind == "computedbool" || f.Kind == "computedstring" {
		return "" // read-only: never sent
	}
	switch f.GoType {
	case "types.List":
		return fmt.Sprintf("putList(ctx, %s, %q, %s.%s, diags.d)", mp, f.Name, mv, f.GoName)
	case "types.Int64":
		return fmt.Sprintf("putInt64(%s, %q, %s.%s)", mp, f.Name, mv, f.GoName)
	case "types.Bool":
		return fmt.Sprintf("putBool(%s, %q, %s.%s)", mp, f.Name, mv, f.GoName)
	default:
		return fmt.Sprintf("putStr(%s, %q, %s.%s)", mp, f.Name, mv, f.GoName)
	}
}

// readStmt maps a response field into the model; mv model var, ov object var.
func readStmt(f field, mv, ov string) string {
	switch f.Kind {
	case "writeonly":
		return fmt.Sprintf("// %s is write-only: preserve the planned value (the API never returns it).", f.Name)
	case "createonly":
		return fmt.Sprintf("// %s is create-only: preserve the planned value (the API never returns it).", f.Name)
	case "computedbool":
		return fmt.Sprintf("%s.%s = boolValDefault(%s, %q)", mv, f.GoName, ov, f.Name)
	}
	switch f.GoType {
	case "types.List":
		return fmt.Sprintf("%s.%s = diags.list(listVal(ctx, %s, %q))", mv, f.GoName, ov, f.Name)
	case "types.Int64":
		return fmt.Sprintf("%s.%s = int64Val(%s, %q)", mv, f.GoName, ov, f.Name)
	case "types.Bool":
		return fmt.Sprintf("%s.%s = boolVal(%s, %q)", mv, f.GoName, ov, f.Name)
	default:
		return fmt.Sprintf("%s.%s = strVal(%s, %q)", mv, f.GoName, ov, f.Name)
	}
}

func renderResource(r resModel) string {
	var b strings.Builder
	p := func(f string, a ...any) { fmt.Fprintf(&b, f+"\n", a...) }

	p(genHeader)
	p("package provider\n")
	p("import (")
	p("\t%q", "context")
	if r.Kind == "singleton" {
		p("\t%q", "github.com/hashicorp/terraform-plugin-framework/path")
	}
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/resource")
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/resource/schema")
	if r.hasCreateOnly() {
		p("\t%q", "github.com/hashicorp/terraform-plugin-framework/resource/schema/planmodifier")
		p("\t%q", "github.com/hashicorp/terraform-plugin-framework/resource/schema/stringplanmodifier")
	}
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/types")
	p("\t%q", "github.com/openwrt-iac/terraform-provider-uapi/internal/client")
	p(")\n")

	if r.Kind == "collection" {
		p("const %sCollection = %q\n", r.Camel, r.Collection)
	} else {
		p("const %sPath = %q\n", r.Camel, "/"+r.Collection)
	}

	p("var (")
	p("\t_ resource.Resource = &%sResource{}", r.Camel)
	p("\t_ resource.ResourceWithConfigure = &%sResource{}", r.Camel)
	p("\t_ resource.ResourceWithImportState = &%sResource{}", r.Camel)
	p(")\n")
	p("type %sResource struct{ client *client.Client }\n", r.Camel)
	p("func New%sResource() resource.Resource { return &%sResource{} }\n", r.Pascal, r.Camel)

	// model
	p("type %sModel struct {", r.Camel)
	p("\tID types.String `tfsdk:\"id\"`")
	p("\tManaged types.Bool `tfsdk:\"managed\"`")
	p("\tETag types.String `tfsdk:\"etag\"`")
	for _, f := range r.Fields {
		p("%s", modelField(f))
	}
	if r.Nested != nil {
		p("\t%s *%s `tfsdk:%q`", pascal(r.Nested.Name), r.Nested.GoType, r.Nested.Name)
	}
	p("}\n")
	if r.Nested != nil {
		p("type %s struct {", r.Nested.GoType)
		for _, f := range r.Nested.Fields {
			p("%s", modelField(f))
		}
		p("}\n")
	}

	p("func (r *%sResource) Metadata(_ context.Context, req resource.MetadataRequest, resp *resource.MetadataResponse) {", r.Camel)
	p("\tresp.TypeName = req.ProviderTypeName + %q", "_"+r.Type)
	p("}\n")
	p("func (r *%sResource) Configure(_ context.Context, req resource.ConfigureRequest, resp *resource.ConfigureResponse) {", r.Camel)
	p("\tr.client = clientFromResourceConfigure(req, resp)")
	p("}\n")

	// schema
	p("func (r *%sResource) Schema(_ context.Context, _ resource.SchemaRequest, resp *resource.SchemaResponse) {", r.Camel)
	p("\tresp.Schema = schema.Schema{")
	p("\t\tDescription: %q,", titleFirst(r.Label)+".")
	p("\t\tAttributes: map[string]schema.Attribute{")
	if r.Kind == "collection" {
		p("\t\t\t\"id\": optionalComputedIDAttribute(),")
	} else {
		p("\t\t\t\"id\": computedIDAttribute(),")
	}
	p("\t\t\t\"managed\": managedAttribute(),")
	p("\t\t\t\"etag\": etagAttribute(),")
	for _, f := range r.Fields {
		p("\t\t\t%s", resAttr(f))
	}
	if r.Nested != nil {
		p("\t\t\t%q: schema.SingleNestedAttribute{", r.Nested.Name)
		p("\t\t\t\tRequired: true,")
		p("\t\t\t\tDescription: %q,", "Match conditions.")
		p("\t\t\t\tAttributes: map[string]schema.Attribute{")
		for _, f := range r.Nested.Fields {
			p("\t\t\t\t\t%s", resAttr(f))
		}
		p("\t\t\t\t},")
		p("\t\t\t},")
	}
	p("\t\t},")
	p("\t}")
	p("}\n")

	// body. The create flag gates create-only inputs: the settable id on every
	// collection (uapi >= 2.2.0) and the deprecated network_interface name. It is
	// emitted only when there is such a field to gate (see needsCreateFlag), else
	// it would be an unused parameter.
	createParam := ""
	if r.needsCreateFlag() {
		createParam = ", create bool"
	}
	p("func (r *%sResource) body(ctx context.Context, m %sModel, diags *diagsink%s) map[string]any {", r.Camel, r.Camel, createParam)
	p("\tout := map[string]any{}")
	// id is settable only on collections, only at create: the server assigns a
	// ULID when it is unset (putStr omits null/unknown) and rejects it at PATCH.
	if r.Kind == "collection" {
		p("\tif create {")
		p("\t\tputStr(out, \"id\", m.ID)")
		p("\t}")
	}
	for _, f := range r.Fields {
		s := bodyStmt(f, "m", "out")
		if s == "" {
			continue
		}
		if f.Kind == "createonly" {
			// create-only fields (e.g. an interface name) set the uci section name
			// and are rejected on PUT/PATCH, so only send them on create.
			p("\tif create {")
			p("\t\t%s", s)
			p("\t}")
		} else {
			p("\t%s", s)
		}
	}
	if r.Nested != nil {
		nv := pascal(r.Nested.Name)
		p("\t%s := map[string]any{}", r.Nested.Name)
		p("\tif m.%s != nil {", nv)
		for _, f := range r.Nested.Fields {
			if s := bodyStmt(f, "m."+nv, r.Nested.Name); s != "" {
				p("\t\t%s", s)
			}
		}
		p("\t}")
		p("\tout[%q] = %s", r.Nested.Name, r.Nested.Name)
	}
	p("\treturn out")
	p("}\n")

	// read
	p("func (r *%sResource) read(ctx context.Context, obj map[string]any, m *%sModel, diags *diagsink) {", r.Camel, r.Camel)
	p("\tm.ID = strVal(obj, \"id\")")
	p("\tm.Managed = boolVal(obj, \"managed\")")
	for _, f := range r.Fields {
		p("\t%s", readStmt(f, "m", "obj"))
	}
	if r.Nested != nil {
		nv := pascal(r.Nested.Name)
		p("\tnested, _ := obj[%q].(map[string]any)", r.Nested.Name)
		p("\tif nested == nil { nested = map[string]any{} }")
		p("\tnm := &%s{}", r.Nested.GoType)
		for _, f := range r.Nested.Fields {
			p("\t%s", readStmt(f, "nm", "nested"))
		}
		p("\tm.%s = nm", nv)
	}
	p("}\n")

	if r.Kind == "collection" {
		p("%s", crudCollection(r))
	} else {
		p("%s", crudSingleton(r))
	}
	return b.String()
}

// bodyCreateArgs returns the trailing argument passed to body() at the Create
// and Update call sites. body() takes a create flag only when the resource has a
// create-only input (a settable id on collections, or a create-only field);
// otherwise both calls (and the signature) omit it. See needsCreateFlag.
func bodyCreateArgs(r resModel) (create, update string) {
	if r.needsCreateFlag() {
		return ", true", ", false"
	}
	return "", ""
}

func crudCollection(r resModel) string {
	c := r.Camel
	coll := c + "Collection"
	createArg, updateArg := bodyCreateArgs(r)
	return fmt.Sprintf(`
func (r *%[1]sResource) Create(ctx context.Context, req resource.CreateRequest, resp *resource.CreateResponse) {
	var plan %[1]sModel
	resp.Diagnostics.Append(req.Plan.Get(ctx, &plan)...)
	if resp.Diagnostics.HasError() { return }
	ds := newDiagsink(&resp.Diagnostics)
	body := r.body(ctx, plan, ds%[4]s)
	if resp.Diagnostics.HasError() { return }
	obj, etag, err := r.client.Post(ctx, "/"+%[2]s, body, "")
	if err != nil { writeErr(&resp.Diagnostics, "creating", %[3]q, err); return }
	r.read(ctx, obj, &plan, ds)
	plan.ETag = types.StringValue(etag)
	resp.Diagnostics.Append(resp.State.Set(ctx, &plan)...)
}

func (r *%[1]sResource) Read(ctx context.Context, req resource.ReadRequest, resp *resource.ReadResponse) {
	var state %[1]sModel
	resp.Diagnostics.Append(req.State.Get(ctx, &state)...)
	if resp.Diagnostics.HasError() { return }
	obj, etag, found, err := r.client.GetObject(ctx, "/"+%[2]s+"/"+state.ID.ValueString())
	if err != nil { resp.Diagnostics.AddError("Error reading %[3]s", err.Error()); return }
	if !found { resp.State.RemoveResource(ctx); return }
	ds := newDiagsink(&resp.Diagnostics)
	r.read(ctx, obj, &state, ds)
	state.ETag = types.StringValue(etag)
	resp.Diagnostics.Append(resp.State.Set(ctx, &state)...)
}

func (r *%[1]sResource) Update(ctx context.Context, req resource.UpdateRequest, resp *resource.UpdateResponse) {
	var plan, state %[1]sModel
	resp.Diagnostics.Append(req.Plan.Get(ctx, &plan)...)
	resp.Diagnostics.Append(req.State.Get(ctx, &state)...)
	if resp.Diagnostics.HasError() { return }
	ds := newDiagsink(&resp.Diagnostics)
	body := r.body(ctx, plan, ds%[5]s)
	if resp.Diagnostics.HasError() { return }
	obj, etag, err := r.client.Put(ctx, "/"+%[2]s+"/"+plan.ID.ValueString(), body, state.ETag.ValueString())
	if err != nil { writeErr(&resp.Diagnostics, "updating", %[3]q, err); return }
	r.read(ctx, obj, &plan, ds)
	plan.ETag = types.StringValue(etag)
	resp.Diagnostics.Append(resp.State.Set(ctx, &plan)...)
}

func (r *%[1]sResource) Delete(ctx context.Context, req resource.DeleteRequest, resp *resource.DeleteResponse) {
	var state %[1]sModel
	resp.Diagnostics.Append(req.State.Get(ctx, &state)...)
	if resp.Diagnostics.HasError() { return }
	if err := r.client.Delete(ctx, "/"+%[2]s+"/"+state.ID.ValueString(), state.ETag.ValueString()); err != nil {
		writeErr(&resp.Diagnostics, "deleting", %[3]q, err)
	}
}

func (r *%[1]sResource) ImportState(ctx context.Context, req resource.ImportStateRequest, resp *resource.ImportStateResponse) {
	importByID(ctx, r.client, %[2]s, %[3]q, req, resp)
}
`, c, coll, r.Label, createArg, updateArg)
}

func crudSingleton(r resModel) string {
	c := r.Camel
	path := c + "Path"
	createArg, updateArg := bodyCreateArgs(r)
	return fmt.Sprintf(`
func (r *%[1]sResource) Create(ctx context.Context, req resource.CreateRequest, resp *resource.CreateResponse) {
	var plan %[1]sModel
	resp.Diagnostics.Append(req.Plan.Get(ctx, &plan)...)
	if resp.Diagnostics.HasError() { return }
	ds := newDiagsink(&resp.Diagnostics)
	body := r.body(ctx, plan, ds%[4]s)
	if resp.Diagnostics.HasError() { return }
	obj, etag, err := r.client.Patch(ctx, %[2]s, body, "")
	if err != nil { writeErr(&resp.Diagnostics, "configuring", %[3]q, err); return }
	r.read(ctx, obj, &plan, ds)
	plan.ETag = types.StringValue(etag)
	resp.Diagnostics.Append(resp.State.Set(ctx, &plan)...)
}

func (r *%[1]sResource) Read(ctx context.Context, req resource.ReadRequest, resp *resource.ReadResponse) {
	var state %[1]sModel
	resp.Diagnostics.Append(req.State.Get(ctx, &state)...)
	if resp.Diagnostics.HasError() { return }
	obj, etag, found, err := r.client.GetObject(ctx, %[2]s)
	if err != nil { resp.Diagnostics.AddError("Error reading %[3]s", err.Error()); return }
	if !found { resp.State.RemoveResource(ctx); return }
	ds := newDiagsink(&resp.Diagnostics)
	r.read(ctx, obj, &state, ds)
	state.ETag = types.StringValue(etag)
	resp.Diagnostics.Append(resp.State.Set(ctx, &state)...)
}

func (r *%[1]sResource) Update(ctx context.Context, req resource.UpdateRequest, resp *resource.UpdateResponse) {
	var plan, state %[1]sModel
	resp.Diagnostics.Append(req.Plan.Get(ctx, &plan)...)
	resp.Diagnostics.Append(req.State.Get(ctx, &state)...)
	if resp.Diagnostics.HasError() { return }
	ds := newDiagsink(&resp.Diagnostics)
	body := r.body(ctx, plan, ds%[5]s)
	if resp.Diagnostics.HasError() { return }
	obj, etag, err := r.client.Patch(ctx, %[2]s, body, state.ETag.ValueString())
	if err != nil { writeErr(&resp.Diagnostics, "updating", %[3]q, err); return }
	r.read(ctx, obj, &plan, ds)
	plan.ETag = types.StringValue(etag)
	resp.Diagnostics.Append(resp.State.Set(ctx, &plan)...)
}

// Delete is a no-op: a singleton cannot be removed; state is just dropped.
func (r *%[1]sResource) Delete(_ context.Context, _ resource.DeleteRequest, _ *resource.DeleteResponse) {}

func (r *%[1]sResource) ImportState(ctx context.Context, req resource.ImportStateRequest, resp *resource.ImportStateResponse) {
	resource.ImportStatePassthroughID(ctx, path.Root("id"), req, resp)
}
`, c, path, r.Label, createArg, updateArg)
}

var runtimeBits = map[string]struct{ model, attr, parse string }{
	"interface": {"networkInterfaceRuntimeModel", "networkInterfaceRuntimeAttribute()", "parseNetworkInterfaceRuntime"},
	"wireless":  {"wirelessInterfaceRuntimeModel", "wirelessInterfaceRuntimeAttribute()", "parseWirelessInterfaceRuntime"},
}

// renderRuntimeDataSource emits a data source with a computed runtime block. It
// uses a dedicated DS model (resource fields + Runtime pointer) since the
// resource model has no runtime attribute.
func renderRuntimeDataSource(r resModel) string {
	rb := runtimeBits[r.Runtime]
	var b strings.Builder
	p := func(f string, a ...any) { fmt.Fprintf(&b, f+"\n", a...) }
	p(genHeader)
	p("package provider\n")
	p("import (")
	p("\t%q", "context")
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/datasource")
	p("\tdsschema %q", "github.com/hashicorp/terraform-plugin-framework/datasource/schema")
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/path")
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/types")
	p("\t%q", "github.com/openwrt-iac/terraform-provider-uapi/internal/client")
	p(")\n")
	// DS model: resource fields + runtime
	p("type %sDSModel struct {", r.Camel)
	p("\tID types.String `tfsdk:\"id\"`")
	p("\tManaged types.Bool `tfsdk:\"managed\"`")
	p("\tETag types.String `tfsdk:\"etag\"`")
	for _, f := range r.dsFields() {
		p("%s", modelField(f))
	}
	p("\tRuntime *%s `tfsdk:\"runtime\"`", rb.model)
	p("}\n")
	p("var (")
	p("\t_ datasource.DataSource = &%sDataSource{}", r.Camel)
	p("\t_ datasource.DataSourceWithConfigure = &%sDataSource{}", r.Camel)
	p(")\n")
	p("type %sDataSource struct{ client *client.Client }\n", r.Camel)
	p("func New%sDataSource() datasource.DataSource { return &%sDataSource{} }\n", r.Pascal, r.Camel)
	p("func (d *%sDataSource) Metadata(_ context.Context, req datasource.MetadataRequest, resp *datasource.MetadataResponse) {", r.Camel)
	p("\tresp.TypeName = req.ProviderTypeName + %q", "_"+r.Type)
	p("}\n")
	p("func (d *%sDataSource) Configure(_ context.Context, req datasource.ConfigureRequest, resp *datasource.ConfigureResponse) {", r.Camel)
	p("\td.client = clientFromDataSourceConfigure(req, resp)")
	p("}\n")
	p("func (d *%sDataSource) Schema(_ context.Context, _ datasource.SchemaRequest, resp *datasource.SchemaResponse) {", r.Camel)
	p("\tresp.Schema = dsschema.Schema{")
	p("\t\tDescription: %q,", "Look up the "+r.Label+".")
	p("\t\tAttributes: map[string]dsschema.Attribute{")
	p("\t\t\t\"id\": dsIDAttribute(),")
	p("\t\t\t\"managed\": dsManagedAttribute(),")
	p("\t\t\t\"etag\": dsComputedString(\"Opaque ETag of the resource's current state.\"),")
	for _, f := range r.dsFields() {
		p("\t\t\t%s", dsAttr(f))
	}
	p("\t\t\t\"runtime\": %s,", rb.attr)
	p("\t\t},")
	p("\t}")
	p("}\n")
	p("func (d *%sDataSource) Read(ctx context.Context, req datasource.ReadRequest, resp *datasource.ReadResponse) {", r.Camel)
	p("\tvar id types.String")
	p("\tresp.Diagnostics.Append(req.Config.GetAttribute(ctx, path.Root(\"id\"), &id)...)")
	p("\tif resp.Diagnostics.HasError() { return }")
	p("\tobj, etag, found, err := d.client.GetObject(ctx, \"/\"+%sCollection+\"/\"+id.ValueString())", r.Camel)
	p("\tif err != nil { resp.Diagnostics.AddError(\"Error reading %s\", err.Error()); return }", r.Label)
	p("\tif !found { resp.Diagnostics.AddError(%q, \"not found\"); return }", r.Label+" not found")
	p("\tvar base %sModel", r.Camel)
	p("\tds := newDiagsink(&resp.Diagnostics)")
	p("\t(&%sResource{}).read(ctx, obj, &base, ds)", r.Camel)
	p("\tbase.ETag = types.StringValue(etag)")
	p("\tm := %sDSModel{", r.Camel)
	p("\t\tID: base.ID, Managed: base.Managed, ETag: base.ETag,")
	for _, f := range r.dsFields() {
		p("\t\t%s: base.%s,", f.GoName, f.GoName)
	}
	p("\t\tRuntime: %s(obj),", rb.parse)
	p("\t}")
	p("\tresp.Diagnostics.Append(resp.State.Set(ctx, &m)...)")
	p("}")
	return b.String()
}

func renderDataSource(r resModel) string {
	if r.Runtime != "" {
		return renderRuntimeDataSource(r)
	}
	var b strings.Builder
	p := func(f string, a ...any) { fmt.Fprintf(&b, f+"\n", a...) }
	p(genHeader)
	p("package provider\n")
	p("import (")
	p("\t%q", "context")
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/datasource")
	p("\tdsschema %q", "github.com/hashicorp/terraform-plugin-framework/datasource/schema")
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/types")
	p("\t%q", "github.com/openwrt-iac/terraform-provider-uapi/internal/client")
	p(")\n")
	p("var (")
	p("\t_ datasource.DataSource = &%sDataSource{}", r.Camel)
	p("\t_ datasource.DataSourceWithConfigure = &%sDataSource{}", r.Camel)
	p(")\n")
	p("type %sDataSource struct{ client *client.Client }\n", r.Camel)
	p("func New%sDataSource() datasource.DataSource { return &%sDataSource{} }\n", r.Pascal, r.Camel)
	p("func (d *%sDataSource) Metadata(_ context.Context, req datasource.MetadataRequest, resp *datasource.MetadataResponse) {", r.Camel)
	p("\tresp.TypeName = req.ProviderTypeName + %q", "_"+r.Type)
	p("}\n")
	p("func (d *%sDataSource) Configure(_ context.Context, req datasource.ConfigureRequest, resp *datasource.ConfigureResponse) {", r.Camel)
	p("\td.client = clientFromDataSourceConfigure(req, resp)")
	p("}\n")
	p("func (d *%sDataSource) Schema(_ context.Context, _ datasource.SchemaRequest, resp *datasource.SchemaResponse) {", r.Camel)
	p("\tresp.Schema = dsschema.Schema{")
	p("\t\tDescription: %q,", "Look up the "+r.Label+".")
	p("\t\tAttributes: map[string]dsschema.Attribute{")
	if r.Kind == "collection" {
		p("\t\t\t\"id\": dsIDAttribute(),")
	} else {
		p("\t\t\t\"id\": dsComputedString(\"Stable id.\"),")
	}
	p("\t\t\t\"managed\": dsManagedAttribute(),")
	p("\t\t\t\"etag\": dsComputedString(\"Opaque ETag of the resource's current state.\"),")
	for _, f := range r.Fields {
		p("\t\t\t%s", dsAttr(f))
	}
	if r.Nested != nil {
		p("\t\t\t%q: dsschema.SingleNestedAttribute{", r.Nested.Name)
		p("\t\t\t\tComputed: true,")
		p("\t\t\t\tDescription: %q,", "Match conditions.")
		p("\t\t\t\tAttributes: map[string]dsschema.Attribute{")
		for _, f := range r.Nested.Fields {
			p("\t\t\t\t\t%s", dsAttr(f))
		}
		p("\t\t\t\t},")
		p("\t\t\t},")
	}
	p("\t\t},")
	p("\t}")
	p("}\n")

	p("func (d *%sDataSource) Read(ctx context.Context, req datasource.ReadRequest, resp *datasource.ReadResponse) {", r.Camel)
	p("\tvar m %sModel", r.Camel)
	p("\tresp.Diagnostics.Append(req.Config.Get(ctx, &m)...)")
	p("\tif resp.Diagnostics.HasError() { return }")
	if r.Kind == "collection" {
		p("\tobj, etag, found, err := d.client.GetObject(ctx, \"/\"+%sCollection+\"/\"+m.ID.ValueString())", r.Camel)
	} else {
		p("\tobj, etag, found, err := d.client.GetObject(ctx, %sPath)", r.Camel)
	}
	p("\tif err != nil { resp.Diagnostics.AddError(\"Error reading %s\", err.Error()); return }", r.Label)
	p("\tif !found { resp.Diagnostics.AddError(%q, \"not found\"); return }", r.Label+" not found")
	p("\tds := newDiagsink(&resp.Diagnostics)")
	p("\t(&%sResource{}).read(ctx, obj, &m, ds)", r.Camel)
	p("\tm.ETag = types.StringValue(etag)")
	p("\tresp.Diagnostics.Append(resp.State.Set(ctx, &m)...)")
	p("}")
	return b.String()
}

func renderRegistration(res, ds []string) string {
	var b strings.Builder
	p := func(f string, a ...any) { fmt.Fprintf(&b, f+"\n", a...) }
	p(genHeader)
	p("package provider\n")
	p("import (")
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/datasource")
	p("\t%q", "github.com/hashicorp/terraform-plugin-framework/resource")
	p(")\n")
	p("func generatedResources() []func() resource.Resource {")
	p("\treturn []func() resource.Resource{")
	for _, c := range res {
		p("\t\t%s,", c)
	}
	p("\t}")
	p("}\n")
	p("func generatedDataSources() []func() datasource.DataSource {")
	p("\treturn []func() datasource.DataSource{")
	for _, c := range ds {
		p("\t\t%s,", c)
	}
	p("\t}")
	p("}")
	return b.String()
}

func exampleResource(r resModel) string {
	var b strings.Builder
	fmt.Fprintf(&b, "resource \"uapi_%s\" \"example\" {\n", r.Type)
	for _, f := range r.Fields {
		if f.Kind != "required" {
			continue
		}
		fmt.Fprintf(&b, "  %s = %s\n", f.Name, exampleValue(f))
	}
	if r.Nested != nil {
		fmt.Fprintf(&b, "  %s = {\n", r.Nested.Name)
		for _, f := range r.Nested.Fields {
			if f.Kind == "required" {
				fmt.Fprintf(&b, "    %s = %s\n", f.Name, exampleValue(f))
			}
		}
		fmt.Fprintf(&b, "  }\n")
	}
	fmt.Fprintf(&b, "}\n")
	return b.String()
}

func exampleValue(f field) string {
	switch f.GoType {
	case "types.List":
		return `["example"]`
	case "types.Int64":
		return "1"
	case "types.Bool":
		return "true"
	default:
		return `"example"`
	}
}

func exampleImport(r resModel) string {
	return fmt.Sprintf("# Import a managed %s by its stable id.\n"+
		"terraform import uapi_%s.example <id>\n\n"+
		"# Importing an anonymous (unmanaged) section adopts it (renames to a stable id).\n"+
		"terraform import uapi_%s.example cfg0a1b2c\n", r.Label, r.Type, r.Type)
}

func exampleDataSource(r resModel) string {
	if r.Kind == "singleton" {
		return fmt.Sprintf("data \"uapi_%s\" \"example\" {}\n", r.Type)
	}
	return fmt.Sprintf("data \"uapi_%s\" \"example\" {\n  id = \"<id>\"\n}\n", r.Type)
}
